import csv, os, re
import numpy as np
from pathlib import Path

DATA_ROOT = Path('/home/mrsar/protein-ag/past-published-data/disease-relevant non-inhibited')

def parse_param(column_name):
    text = column_name.strip()
    m = re.search(r'(\d+(?:\.\d+)?)\s*uM', text, re.IGNORECASE)
    if m: return float(m.group(1))
    m = re.search(r'(\d+(?:\.\d+)?)\s*mM', text, re.IGNORECASE)
    if m: return float(m.group(1)) * 1000.0
    m = re.search(r'(\d+(?:\.\d+)?)\s*mg/mL', text, re.IGNORECASE)
    if m: return float(m.group(1))
    m = re.search(r'(\d+(?:\.\d+)?)\s*ng/ul', text, re.IGNORECASE)
    if m: return float(m.group(1))
    m = re.search(r'pH\s+(\d+(?:\.\d+)?)', text, re.IGNORECASE)
    if m: return float(m.group(1))
    m = re.search(r'(\d+(?:\.\d+)?)\s*%', text)
    if m: return float(m.group(1))
    m = re.search(r':\s*(\d+(?:\.\d+)?)\s*$', text)
    if m: return float(m.group(1))
    return None

for dirpath, _, filenames in os.walk(DATA_ROOT):
    if 'fit.tsv' in filenames:
        path = Path(dirpath) / 'fit.tsv'
        with open(path, newline='') as f:
            reader = csv.reader(f, delimiter='\t')
            header = next(reader)
        resp = header[1:]
        parsed = [parse_param(h) for h in resp]
        n_cols = len(resp)
        all_parsed = all(p is not None for p in parsed)
        name = str(path.parent.relative_to(DATA_ROOT))
        if not all_parsed:
            print(f'NON-NUMERIC: {name} cols={n_cols} headers={resp[:3]}')
        else:
            vals = [float(p) for p in parsed]
            if len(set(vals)) == 1:
                print(f'SINGLE-VAL: {name} x1={vals[0]:.2f} ncols={n_cols}')
"

